import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useSelector } from 'react-redux';
import { dotnetApi } from '../api/axios';
import { ENDPOINTS } from '../api/config';
import { toast } from 'react-toastify';
import './Support.css';

const Support = () => {
  const [feedbackText, setFeedbackText] = useState('');
  const [sending, setSending] = useState(false);
  const { user } = useSelector((state) => state.auth);
  const navigate = useNavigate();

  const handleSubmitFeedback = async (e) => {
    e.preventDefault();
    if (!feedbackText.trim()) {
      toast.warn('Please enter your feedback');
      return;
    }
    setSending(true);
    try {
      await dotnetApi.post(ENDPOINTS.POST_FEEDBACK, {
        message: feedbackText.trim(),
        email: user?.email,
        name: user?.fullName || '',
      });
      toast.success('Feedback submitted! Thank you.');
      setFeedbackText('');
    } catch (error) {
      toast.error('Failed to submit feedback');
    }
    setSending(false);
  };

  return (
    <div className="support-page">
      <div className="support-header">
        <button className="support-back" onClick={() => navigate(-1)}>←</button>
        <h1 className="support-title">Support</h1>
      </div>

      {/* FAQ */}
      <div className="support-section">
        <h2 className="support-section-title">Frequently Asked Questions</h2>
        {[
          { q: 'How do I change my profile photo?', a: 'Go to Profile > Edit Profile, then tap on your profile picture to upload a new one.' },
          { q: 'How do I make a video call?', a: 'Open a chat with a friend and tap the video call icon in the header.' },
          { q: 'How do I start a live stream?', a: 'Go to your profile or home screen and look for the Live Streaming option.' },
          { q: 'How do I create a group?', a: 'Go to Groups > Create Group, enter a name and description, then tap Done.' },
          { q: 'How do I change my password?', a: 'Go to Settings > Edit Profile, or use the Forgot Password option on the login screen.' },
        ].map((faq, i) => (
          <details key={i} className="support-faq">
            <summary className="support-faq-q">{faq.q}</summary>
            <p className="support-faq-a">{faq.a}</p>
          </details>
        ))}
      </div>

      {/* Feedback */}
      <div className="support-section">
        <h2 className="support-section-title">Send Feedback</h2>
        <form onSubmit={handleSubmitFeedback}>
          <textarea
            className="support-feedback-input"
            placeholder="Tell us how we can improve..."
            value={feedbackText}
            onChange={(e) => setFeedbackText(e.target.value)}
            rows={4}
          />
          <button type="submit" className="support-submit-btn" disabled={sending}>
            {sending ? 'Sending...' : 'Submit Feedback'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default Support;
